@using sv_c7e85cad4af94c5d9a849007a0079fb3.Models

<nav aria-label="Application steps" class="mb-4">
    <ol class="step-indicator d-flex list-unstyled justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep && !isCompleted;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
                @onclick="() => HandleStepClick(step)"
                role="button"
                style="cursor: @(isCompleted ? "pointer" : "default")">
                <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : isCurrent ? "fw-bold text-primary" : "text-success")">
                    @StepNames[i]
                </small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@using sv_c7e85cad4af94c5d9a849007a0079fb3.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@Entry.EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
