@using sv_c7e85cad4af94c5d9a849007a0079fb3.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? "" }" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone is required."; return; }
        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        IsValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync(Model);
        }
        finally
        {
            IsValidating = false;
        }
    }
}

