@using sv_c7e85cad4af94c5d9a849007a0079fb3.Models

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
            </dl>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small>@r.Email | @r.Phone</small>
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = new();
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = new();
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }
    [Parameter] public string? ErrorMessage { get; set; }
}

@code {
    private async Task HandleSubmit() => await OnSubmit.InvokeAsync();
}

arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_c7e85cad4af94c5d9a849007a0079fb3.Components.Apply
@using sv_c7e85cad4af94c5d9a849007a0079fb3.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="HandlePersonalNext" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="HandleWorkNext"
                             OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="HandleReferencesNext"
                            OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep CoverLetter="coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        IsSubmitting="isSubmitting"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        ErrorMessage="submitError"
                        OnEdit="GoToStep"
                        OnBack="() => GoToStep(4)"
                        OnSubmit="HandleSubmit" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    // Form data
    private PersonalInfo personalInfo = new("", "", "", "");
    private List<WorkEntry> workEntries = new() { new("", "", DateTime.Today, null, "") };
    private List<Reference> references = new() { new("", "", "", ""), new("", "", "", "") };
    private string coverLetter = "";

    // Submission state
    private bool isSubmitting;
    private bool isSubmitted;
    private int applicationId;
    private string? submitError;

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void HandlePersonalNext(PersonalInfo info)
    {
        personalInfo = info;
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleWorkNext(List<WorkEntry> entries)
    {
        workEntries = entries;
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            var application = new JobApplication(
                personalInfo,
                new WorkHistory(workEntries),
                references,
                coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
            completedSteps.Add(5);
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

